-- ==============================================================
-- seed.sql - 读取数据
-- 数据来源: SMILES.csv + descriptors.csv (32 compounds)
-- ==============================================================

-- 清空表数据
DELETE FROM molecular_descriptors;
DELETE FROM compounds;

-- ==============================================================
-- 插入化合物主表数据
-- ==============================================================


-- ==============================================================
-- 插入分子描述符表数据 
-- ==============================================================


-- ==============================================================
-- 数据验证
-- ==============================================================
SELECT '=== Import complete ===' AS status;
SELECT COUNT(*) || ' compounds loaded' AS info FROM compounds;
SELECT COUNT(*) || ' descriptors loaded' AS info FROM molecular_descriptors;

-- Lipinski规则通过率
SELECT
    COUNT(*) AS total_compounds,
    SUM(CASE WHEN mw <= 500 AND mol_log_p <= 5
              AND h_bond_donors <= 5 AND h_bond_acceptors <= 10
         THEN 1 ELSE 0 END) AS passes_lipinski
FROM compounds;